INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311002, 8, 0, 11, 0, 0.5, 311, 102711, 0, 0, "この広い会場のどこかに\nあのおかたの存在を感じますわ……");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311003, "", "", 91, "", "", 311, 311002, "", "", "");
