INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311005, 0, 0.2, 3, 1, "", 311, 100911, 0, "nop_11_anna_huhuStand_loop", "nop_11_anna_huhuStand_in");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311006, 8, 0, 11, 0, 0.5, 311, 100911, 0, 0, "疼く……疼くぞ！\n我が魔眼が新たなる年を祝えと……！");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311007, "", "", 91, "", "", 311, 311006, "", "", "");
