INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311009, 1, 0.2, 3, "", "", 311, 101311, "", "", "nop_talk_joy2");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311010, 8, 0, 11, 0, 0.5, 311, 101311, 0, 0, "アンナたそアンナたそ！\nおせち料理、美味しそうですぞ！\nさあ、おあがりよ！！");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311011, "", "", 91, "", "", 311, 311010, "", "", "");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311012, 1, 0.2, 3, "", "", 311, 101311, "", "", "nop_idle_joy_normal");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311013, 1, 0.2, 3, "", "", 311, 105111, "", "", "nop_talk_thinking");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311014, 8, 0, 11, 0, 0.5, 311, 105111, 0, 0, "医食同源……って知ってるかしら？\n長寿を願う料理には、なにかしらの\n効能があるものも多いのよ。");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311015, "", "", 91, "", "", 311, 311014, "", "", "");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311016, 1, 0.2, 3, "", "", 311, 105111, "", "", "nop_idle_thinking");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312001, 8, 0, 11, 0, 0.5, 312, 101831, 0, 0, "素敵な新年会ね～\n他の学校の人たちも来ているようだし\nお話を伺いに行こうかしら？");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312002, 1, 0.2, 3, "", "", 312, 101831, "", "", "nop_talk_joy1");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312003, "", "", 91, "", "", 312, 312001, "", "", "");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312004, 1, 0.2, 3, 1, "", 312, 101831, "", "", "nop_idle_joy1");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312005, 8, 0, 11, 0, 0.5, 312, 101611, 0, 0, "見て見てミサキっち！\nあそこの料理すっごく美味しそう！");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312006, 1, 0.2, 3, "", "", 312, 101611, "", "", "nop_talk_surprise_kira");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312007, "", "", 91, "", "", 312, 312005, "", "", "");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312008, 1, 0.2, 3, 1, "", 312, 101611, "", "", "nop_idle_surprise_kira");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312009, 8, 0, 11, 0, 0.5, 312, 105011, 0, 0, "えー？　でもあれって野菜じゃない？\n別に、大人のレディだから\n食べられないわけじゃないけど？");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312010, 1, 0.2, 3, "", "", 312, 105011, "", "", "nop_talk_sad");
