INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312012, 1, 0.2, 3, "", "", 312, 105011, "", "", "nop_talk_tsun_pain");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312013, "", "", 91, "", "", 312, 312009, "", "", "");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312014, 1, 0.2, 3, 1, "", 312, 105011, "", "", "nop_idle_sad");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (313001, 8, 0, 11, 0, 0.5, 313, 105331, 0, 0, "立派な新年会ではないか。\n我々もこの場に相応しく\n振る舞わなければな！");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (313002, 0, 0.2, 3, 1, "", 313, 105331, 0.2, "nop_13_monica_talk_doya_loop", "nop_13_monica_talk_doya");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (313003, "", "", 91, "", "", 313, 313001, "", "", "");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (313004, 1, 0.2, 3, 1, "", 313, 105331, "", "", "nop_idle_doya");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (313005, 8, 0, 11, 0, 0.5, 313, 103031, 0, 0, "おせちといえばトーゴクデース！\nオーエド町のみなさんにも\n新年のゴアイサツしないとデスね！");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (313006, 1, 0.2, 3, "", "", 313, 103031, "", "", "nop_talk_joy1");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (313007, "", "", 91, "", "", 313, 313005, "", "", "");
